                "name": "Rancho Cienega Sports Complex",
                "description": "Park/Facility in Baldwin Hills / Crenshaw",
                "type": "landmark",
                "address": "5001 West Obama Boulevard, 90016, Los Angeles, CA",
                "lat": 34.0229782,
                "lng": -118.3514764,
